// --- ROUTER & RENDERER ---
const render = () => {
  const app = document.getElementById('app');
  if (!app) return;

  const header = Header();
  const cart = CartSidebar();
  let content = '';

  const path = state.currentRoute.split('?')[0];

  if (path === '#/' || path === '') content = Home();
  else if (path === '#/shop') content = `<div class="p-20 text-center font-black">Shop Page Coming Soon...</div>`;
  else if (path.startsWith('#/product/')) content = `<div class="p-20 text-center font-black">Product Details Simulation</div>`;
  else content = `<div class="p-20 text-center font-black">404 - Page Not Found</div>`;

  app.innerHTML = `
    <div class="min-h-screen flex flex-col">
      ${header}
      <main class="flex-grow">${content}</main>
      ${cart}
    </div>
  `;

  // Attach dynamic events
  document.getElementById('cart-toggle-btn')?.addEventListener('click', () => updateState({ isCartOpen: true }));
};

// --- ACTION HANDLERS (Global for HTML tags) ---
(window as any).addToCart = (productId: string) => {
  const p = state.products.find(x => x.id === productId);
  if (!p) return;
  const existing = state.cart.find(x => x.id === productId);
  if (existing) {
    updateState({ cart: state.cart.map(x => x.id === productId ? { ...x, quantity: x.quantity + 1 } : x) });
  } else {
    updateState({ cart: [...state.cart, { ...p, quantity: 1 }], isCartOpen: true });
  }
};

(window as any).closeCart = () => updateState({ isCartOpen: false });

(window as any).updateQty = (id: string, delta: number) => {
  const updated = state.cart.map(x => x.id === id ? { ...x, quantity: Math.max(0, x.quantity + delta) } : x).filter(x => x.quantity > 0);
  updateState({ cart: updated });
};

// --- INITIALIZATION ---
window.addEventListener('hashchange', () => {
  state.currentRoute = window.location.hash;
  render();
});

fetchData();
render();

